// 1. 实现完整的WebSocket服务
export class RealtimeService {
  private connections: Set<WebSocket> = new Set();
  private subscriptions: Map<string, Set<WebSocket>> = new Map();

  // 订阅管理
  subscribe(ws: WebSocket, channel: string) {
    if (!this.subscriptions.has(channel)) {
      this.subscriptions.set(channel, new Set());
    }
    this.subscriptions.get(channel)!.add(ws);
  }

  unsubscribe(ws: WebSocket, channel?: string) {
    if (channel) {
      this.subscriptions.get(channel)?.delete(ws);
    } else {
      this.connections.delete(ws);
    }
  }

  // 广播到所有连接
  broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data });

    this.connections.forEach(ws => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message);
      }
    });
  }

  // 广播到特定频道
  broadcastToChannel(channel: string, event: string, data: any) {
    const subscribers = this.subscriptions.get(channel);
    if (!subscribers) return;

    const message = JSON.stringify({ event, data });
    subscribers.forEach(ws => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message);
      }
    });
  }

  // 心跳检测
  startHeartbeat() {
    setInterval(() => {
      this.broadcast('ping', { timestamp: Date.now() });
    }, 30000);
  }
}

// 2. 在server.ts中注册WebSocket路由
